final:
module gray_counter_12(
   input                clk,
   input                rst_n,

   output reg [11:0]    Q  
);
    reg [11:0] unused_binary_counter;

    always @(posedge clk) begin
        if (!rst_n) unused_binary_counter <= 12'b0;
        else unused_binary_counter <= unused_binary_counter + 1;
    end

    always @(*) begin
        Q = unused_binary_counter ^ (unused_binary_counter >> 1);
    end
endmodule
